/**
 * Validated tenant configuration types.
 */

export interface TenantSettings {
  branding?: {
    logoUrl?: string;
    primaryColor?: string;
    displayName?: string;
  };
  features?: Record<string, boolean>;
  integrations?: {
    webhookUrl?: string;
    ssoProvider?: string;
  };
  retention?: {
    days?: number;
  };
  auth?: {
    oidc?: {
      issuerUrl: string;
      clientId: string;
      clientSecret: string;
      redirectUri: string;
      scopes: string[];
      logoutUrl?: string;
      claimMappings?: Record<string, string>;
    };
    sessionTtlSeconds?: number;
  };
  ai?: {
    provider?: "anthropic" | "openai" | "azure-openai";
    model?: string;
    temperature?: number;
    maxRetries?: number;
    gatewayUrl?: string;
  };
