              mod.status === "learning" ||
              mod.status === "content-generating" ||
              mod.status === "scenario-active" ||
              mod.status === "quiz-active"
            ) {
              indicator = (
                <span
                  style={{ color: "#1e40af", display: "flex", alignItems: "center" }}
