                        aria-label={`Status: ${sess.status}`}
                      >
                        {sess.status.toUpperCase()}
                      </span>
                      {pct != null && (
                        <div style={{ fontSize: "0.875rem", color: "#555" }}>
                          {STRINGS.historyScoreLabel} {pct}%
